// ── MODULE METADATA & HELPERS ─────────────────────────────────────────────────
export type ModuleId = 'business' | 'academic' | 'speaking' | 'grammar'

export interface ModuleMeta {
  id: ModuleId
  title: string
  description: string
  icon: LucideIcon
  levels: string
  lessonCount: number
  lessons: ModuleLesson[]
}

export const MODULES: ModuleMeta[] = [
  {
    id: 'business',
    title: 'Business English',
    description: 'Деловая коммуникация: переговоры, презентации, отчёты',
    icon: Briefcase,
    levels: 'B1–C1',
    lessonCount: BUSINESS_LESSONS.length,
    lessons: BUSINESS_LESSONS,
  },
  {
    id: 'academic',
    title: 'Academic Writing',
    description: 'IELTS и TOEFL: эссе, Task 1 & 2, академический стиль',
    icon: GraduationCap,
    levels: 'B2–C1',
    lessonCount: ACADEMIC_LESSONS.length,
    lessons: ACADEMIC_LESSONS,
  },
  {
    id: 'speaking',
    title: 'Speaking Club',
    description: 'Разговорная практика: дискуссии, истории, переговоры',
    icon: MessagesSquare,
    levels: 'A2–C1',
    lessonCount: SPEAKING_LESSONS.length,
    lessons: SPEAKING_LESSONS,
  },
  {
    id: 'grammar',
    title: 'Grammar Deep Dive',
    description: 'Глубокое погружение: артикли, времена, условные, инверсия',
    icon: Type,
    levels: 'B1–C1',
    lessonCount: GRAMMAR_LESSONS.length,
    lessons: GRAMMAR_LESSONS,
  },
]

export function getModuleLessons(moduleId: ModuleId): ModuleLesson[] {
  return MODULES.find(m => m.id === moduleId)?.lessons ?? []
}

export function getModuleLesson(moduleId: ModuleId, lessonId: string): ModuleLesson | undefined {
  return getModuleLessons(moduleId).find(l => l.id === lessonId)
}

export const ALL_MODULE_LESSONS: ModuleLesson[] = [
  ...BUSINESS_LESSONS,
  ...ACADEMIC_LESSONS,
  ...SPEAKING_LESSONS,
  ...GRAMMAR_LESSONS,
]
